#include <stdio.h>
#include <stdlib.h>

int main(){
    const int MAXN = 10000000;
    unsigned char *isPrime = (unsigned char*)malloc((MAXN+1)*sizeof(unsigned char));
    int *pref = (int*)malloc((MAXN+1)*sizeof(int));
    for(int i=0;i<=MAXN;i++) isPrime[i]=1;
    isPrime[0]=isPrime[1]=0;
    for(int i=2;i*i<=MAXN;i++) if(isPrime[i]) for(int j=i*i;j<=MAXN;j+=i) isPrime[j]=0;
    pref[0]=0;
    for(int i=1;i<=MAXN;i++) pref[i]=pref[i-1]+isPrime[i];
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int half = N/2;
        int ans = (N>=4 ? 1 : 0) + (pref[N] - pref[half]);
        printf("%d\n", ans);
    }
    free(isPrime);
    free(pref);
    return 0;
}

