import java.io.*;
import java.util.*;
public class Main {
    static final int MAXN = 10_000_000;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        boolean[] isPrime = new boolean[MAXN+1];
        Arrays.fill(isPrime, true);
        isPrime[0]=isPrime[1]=false;
        for(int i=2;i*i<=MAXN;i++) if(isPrime[i]) for(int j=i*i;j<=MAXN;j+=i) isPrime[j]=false;
        int[] pref = new int[MAXN+1];
        for(int i=1;i<=MAXN;i++) pref[i]=pref[i-1]+(isPrime[i]?1:0);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            int half = N/2;
            int ans = (N>=4?1:0) + (pref[N]-pref[half]);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

