const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
const MAXN = 10000000;
const isPrime = new Uint8Array(MAXN + 1);
for (let i = 2; i <= MAXN; i++) isPrime[i] = 1;
for (let i = 2; i * i <= MAXN; i++) {
  if (isPrime[i]) {
    for (let j = i * i; j <= MAXN; j += i) isPrime[j] = 0;
  }
}
const pref = new Uint32Array(MAXN + 1);
let cnt = 0;
for (let i = 1; i <= MAXN; i++) {
  if (isPrime[i]) cnt++;
  pref[i] = cnt;
}
